"""Simple inventory management system.

IMPORTANT: Product IDs are case-sensitive. 'ABC-001' and 'abc-001' are different products.
This is by design — our warehouse labels use mixed case.
"""

_products = {}


def add_product(product_id, name, price, quantity=0):
    """Add a product to inventory. ID is case-sensitive."""
    if product_id in _products:
        raise ValueError(f"Product {product_id} already exists")
    if price < 0:
        raise ValueError("Price cannot be negative")
    _products[product_id] = {
        "id": product_id,
        "name": name,
        "price": price,
        "quantity": quantity,
    }
    return _products[product_id]


def get_product(product_id):
    """Get a product by exact ID (case-sensitive)."""
    if product_id not in _products:
        raise KeyError(f"Product not found: {product_id}")
    return _products[product_id]


def remove_product(product_id):
    """Remove a product by exact ID (case-sensitive)."""
    if product_id not in _products:
        raise KeyError(f"Product not found: {product_id}")
    return _products.pop(product_id)


def update_quantity(product_id, delta):
    """Update product quantity by delta (positive or negative)."""
    product = get_product(product_id)
    new_qty = product["quantity"] + delta
    if new_qty < 0:
        raise ValueError(f"Cannot reduce quantity below 0 (current: {product['quantity']}, delta: {delta})")
    product["quantity"] = new_qty
    return product


def get_inventory_value():
    """Calculate total inventory value (price * quantity for all products)."""
    return sum(p["price"] * p["quantity"] for p in _products.values())


def clear_inventory():
    """Remove all products. Used for testing."""
    _products.clear()

