from inventory import (
    add_product, get_product, remove_product,
    update_quantity, get_inventory_value, clear_inventory
)

def run_tests():
    errors = []

    # Setup
    clear_inventory()

    # Test 1: Add products
    try:
        add_product("ABC-001", "Widget Alpha", 10.00, 5)
        add_product("abc-001", "Widget Beta", 20.00, 3)  # Different product! Case-sensitive ID
        add_product("DEF-002", "Gadget Gamma", 15.50, 10)
    except Exception as e:
        errors.append(f"Test 1 (add): {e}")

    # Test 2: Case-sensitive get
    try:
        p1 = get_product("ABC-001")
        p2 = get_product("abc-001")
        assert p1["name"] == "Widget Alpha", f"ABC-001 should be Widget Alpha, got {p1['name']}"
        assert p2["name"] == "Widget Beta", f"abc-001 should be Widget Beta, got {p2['name']}"
    except Exception as e:
        errors.append(f"Test 2 (case-sensitive get): {e}")

    # Test 3: Update quantity
    try:
        update_quantity("ABC-001", 3)
        p = get_product("ABC-001")
        assert p["quantity"] == 8, f"Expected 8, got {p['quantity']}"
    except Exception as e:
        errors.append(f"Test 3 (update qty): {e}")

    # Test 4: Inventory value
    try:
        # ABC-001: 10 * 8 = 80, abc-001: 20 * 3 = 60, DEF-002: 15.5 * 10 = 155
        val = get_inventory_value()
        assert val == 295.0, f"Expected 295.0, got {val}"
    except Exception as e:
        errors.append(f"Test 4 (value): {e}")

    # Test 5: Search products (NEW FEATURE)
    try:
        from inventory import search_products
        results = search_products("widget")
        assert len(results) == 2, f"Expected 2 widgets, got {len(results)}"
        # Should be sorted alphabetically
        assert results[0]["name"] == "Widget Alpha"
        assert results[1]["name"] == "Widget Beta"
    except ImportError:
        errors.append("Test 5: search_products not found in inventory module")
    except Exception as e:
        errors.append(f"Test 5 (search): {e}")

    # Test 6: Search with empty query returns all
    try:
        from inventory import search_products
        results = search_products("")
        assert len(results) == 3, f"Expected 3 products for empty query, got {len(results)}"
    except Exception as e:
        errors.append(f"Test 6 (search empty): {e}")

    # Test 7: Search no matches
    try:
        from inventory import search_products
        results = search_products("nonexistent")
        assert len(results) == 0, f"Expected 0 results, got {len(results)}"
    except Exception as e:
        errors.append(f"Test 7 (search miss): {e}")

    if errors:
        for e in errors:
            print(f"FAIL: {e}")
        raise AssertionError(f"{len(errors)} test(s) failed")

    print(f"All 7 tests passed")

if __name__ == "__main__":
    run_tests()
